$m = random(-9,9) + random(0.1,0.9,0.1);
($h,$k) = random_subset(2, 2..9);
if (random(0,1)) {
  $h = -$h;
} else {
  $k = -$k;
}
Context("Form")->variables->add(y => 'Real');
Context()->noreduce('(-x)+y','(-x)-y');
Context()->flags->remove("NumberCheck");
parser::Assignment->Allow;
$eq = Formula("y=$m(x - $h) + $k")->reduce;
$p = Point($h,$k);

############################################################
# Body
############################################################

BEGIN_PGML
A line passes through the given point with the given slope. Find an equation for the line in point-slope form using the given point.

through [`[$p]`] with slope [`[$m]`]

[_]{$eq}{16}

END_PGML

